-- 2026-06-19: shoulder_subacromial_pain_conservative — фазы «Путь» + структурированные критерии перехода.
-- Shoulder protocols (субакромиальный болевой синдром, КОНСЕРВАТИВНОЕ ведение).
--
-- Источник: PROTOCOLS досье субакромиального синдрома + PROTOCOLS/shoulder/_extractions.json
-- (объект "shoulder_subacromial_pain_conservative").
--
-- КОНСЕРВАТИВНЫЙ протокол — ОПЕРАЦИИ НЕТ. Хирургия (декомпрессия) — лишь резерв при неудаче
-- 3–6 мес терапии, её эффективность над плацебо оспаривается; хирургический путь не структурирован.
-- anchor symptom_driven: недели привязаны к старту программы, прогрессия идёт ПО СИМПТОМАМ И
-- КРИТЕРИЯМ (боль, амплитуда, контроль лопатки), а не к календарю/дате операции.
--
-- 4 фазы (нумерация С 1, БЕЗ phase 0): 1 Купирование боли и базовая амплитуда →
-- 2 Полная амплитуда и контроль лопатки → 3 Прогрессивное укрепление → 4 Возврат к спорту/работе.
-- Фаза 4 имеет критерии (последний переход «выписки»). Контент в ПАЦИЕНТСКОМ регистре
-- (без клинич. жаргона PROM/ER/IR/scapular/painful arc — раскрыт по-русски) — Vadim калибрует
-- через AdminContent.
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
--
-- Классификация критериев: авто-проверяемо сегодня только боль ВАШ → criterion_type
-- 'measurement' (measurement_type='vas_score' — КАК В ACL/knee-seed, чтобы D2 читал единый код
-- против pain_entries.vas_score). Остальные числовые пороги (амплитуда в градусах, % симметрии,
-- соотношение ER/IR) система не хранит → 'instructor_check' с порогом в тексте label (куратор
-- вводит очно). Субъективные ощущения пациента → 'self_report'.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee/другие shoulder program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_subacromial_pain_conservative (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
