ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (купирование боли → полная амплитуда)
  (1, 'rest_night_pain_down',   'Уменьшилась боль в покое и ночью по сравнению с началом',                    'self_report',      NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Уменьшилась боль в покое и ночью по сравнению с началом?', 'Сравните с тем, как было в начале программы', 10::smallint, TRUE),
  (1, 'lift_to_shoulder',       'Можете поднять руку до уровня плеча без резкой боли',                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете поднять руку до уровня плеча без резкой боли?', 'Без рывка и резкой боли', 20::smallint, TRUE),
  (1, 'rest_pain_le3',          'Боль в покое держится на приемлемом уровне (≤ 3 из 10)',                     'measurement',      'vas_score', 'pain', '<=', 3::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'isometrics_tolerated',   'Мягкая работа мышц плеча переносится без обострения (боль не нарастает за сутки)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'passive_rom_near_full',  'Подвижность близка к полной без выраженного болевого ограничения',           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),
  -- Фаза 2 → Фаза 3 (полная амплитуда → укрепление)
  (2, 'active_flexion_150',     'Подъём руки вперёд не менее 150°',                                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'active_abduction_150',   'Подъём руки в сторону не менее 150°',                                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'no_painful_arc',         'Нет выраженной болезненной зоны при подъёме руки в сторону',                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'scapular_rhythm_ok',     'Лопатка двигается правильно и плавно (нет нарушения ритма)',                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'shoulder_level_adl',     'Можете выполнять бытовые движения на уровне плеч без боли',                  'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете выполнять движения на уровне плеч в быту без боли?', 'Например, достать предмет с полки', 50::smallint, TRUE),
  -- Фаза 3 → Фаза 4 (укрепление → возврат к активности)
  (3, 'full_painless_rom',      'Полный объём движения рукой без боли во всех направлениях',                  'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'overhead_no_pain',       'Можете работать рукой над головой без боли при умеренной нагрузке',          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете работать рукой над головой без боли при умеренной нагрузке?', 'Например, повесить вещь на верхнюю полку', 20::smallint, TRUE),
  (3, 'er_ir_ratio_066',        'Баланс силы вращателей плеча: соотношение наружного к внутреннему ≥ 0.66 (ориентир 0.66–0.75)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE),
  (3, 'strength_symmetry_90',   'Сила больной руки не менее 90% от здоровой',                                'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, FALSE),
  (3, 'load_pain_acceptable',   'Боль при нагрузке не превышает приемлемого уровня и уходит к утру',          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль при нагрузке не превышает приемлемого уровня и уходит к утру?', 'Допустимо до 5 из 10 с возвратом за сутки', 50::smallint, TRUE),
  -- Фаза 4 (возврат к полной активности / спорту / работе — финальные критерии «выписки»)
  (4, 'rom_strength_symmetry',  'Полный безболезненный объём движений и силовой баланс восстановлены (для спорта над головой — амплитуда вращения в пределах ±5–10° от здоровой руки)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (4, 'confident_sport_load',   'Уверены в плече при нагрузке вашего спорта или работы',                      'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Уверены в плече при спорт- или работа-специфичной нагрузке?', 'Без страха и боли при привычных движениях', 20::smallint, TRUE),
  (4, 'spadi_dash_improved',    'Самочувствие плеча по опроснику SPADI/DASH заметно улучшилось (оценивает куратор)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_subacromial_pain_conservative' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
